import React from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Topnav from "../components/Topnav";
import Footer from "../components/Footer";

function Result() {
  const navigate = useNavigate();
  const location = useLocation();
  const {
    gem_prediction,
    gem_confidence,
    shape_prediction,
    shape_confidence,
    image,
    show_shape,
  } = location.state || {};

  const gemConfidencePercent   = (gem_confidence * 100)?.toFixed(1) ?? "—";
  const shapeConfidencePercent = show_shape ? (shape_confidence * 100)?.toFixed(1) ?? "—" : null;

  return (
    <>
      <Topnav />

      <main className="min-h-[80vh] bg-gray-50/70 flex items-center justify-center py-10 px-5">
        <div className="w-full max-w-lg bg-white rounded-2xl shadow-xl p-6 sm:p-8 md:p-10 text-center">
          <h1 className="text-2xl sm:text-3xl font-bold text-gray-800 mb-6">
            Gem Analysis Result
          </h1>

          {image && (
            <div className="mb-6">
              <img
                src={URL.createObjectURL(image)}
                alt={gem_prediction || "Gem"}
                className="w-52 h-52 sm:w-64 sm:h-64 mx-auto rounded-full object-cover shadow-lg border-4 border-blue-50"
              />
            </div>
          )}

          <div className="space-y-6 text-base sm:text-lg">
            <div>
              <p className="text-gray-600 text-sm sm:text-base">Gem</p>
              <p className="text-2xl sm:text-3xl font-bold text-blue-700 mt-1">
                {gem_prediction || "Unknown"}
              </p>
              <p className="text-gray-600 mt-1">
                Confidence: <span className="font-semibold">{gemConfidencePercent}%</span>
              </p>
            </div>

            {show_shape && shape_prediction && (
              <div>
                <p className="text-gray-600 text-sm sm:text-base">Shape / Cut</p>
                <p className="text-2xl sm:text-3xl font-bold text-blue-700 capitalize mt-1">
                  {shape_prediction}
                </p>
                <p className="text-gray-600 mt-1">
                  Confidence: <span className="font-semibold">{shapeConfidencePercent}%</span>
                </p>
              </div>
            )}
          </div>

          <button
            onClick={() => navigate("/imageuploader")}
            className="mt-8 sm:mt-10 px-8 py-3 bg-blue-600 hover:bg-blue-700 text-white text-base sm:text-lg font-semibold rounded-full shadow transition-all"
          >
            Analyze Another Gem
          </button>
        </div>
      </main>

      <Footer />
    </>
  );
}

export default Result;
